+/// Copy file preserving metadata (copy2 in Python)
+pub fn copy2(allocator: Allocator, src: []const u8, dst: []const u8) ![]const u8 {
+    // For now, same as copy - Zig's copyFile preserves what it can
+    return copy(allocator, src, dst);
+}
